#!/usr/bin/env node
/**
 * Generates mcp/src/data/component-tokens.generated.ts from the component token
 * tier (src/tokens/components/*.css). Every component token becomes catalog data
 * (name + default value + the nearest CSS comment as its description) so the MCP
 * `get_component` tool can tell an agent EXACTLY which theme knobs a component
 * exposes. Run by check:mcp-token-sync; never hand-edit the generated file.
 *
 *   node scripts/gen-component-tokens.mjs           # write
 *   node scripts/gen-component-tokens.mjs --check    # exit 1 if stale
 */
import { readFileSync, writeFileSync, globSync } from "node:fs";

const OUT = "mcp/src/data/component-tokens.generated.ts";

function parse(file) {
  const text = readFileSync(file, "utf8");
  const re = /\/\*([\s\S]*?)\*\/|(--[a-z0-9-]+)\s*:\s*([^;]+);/g;
  const items = [];
  let comment = "";
  for (const m of text.matchAll(re)) {
    if (m[1] !== undefined) {
      comment = m[1].replace(/\s+/g, " ").trim();
    } else {
      items.push({ name: m[2], value: m[3].replace(/\s+/g, " ").trim(), description: comment });
    }
  }
  return items;
}

const files = globSync("src/tokens/components/*.css").sort();
const tokens = files.flatMap(parse);

const body =
  "// AUTO-GENERATED by scripts/gen-component-tokens.mjs — do not edit.\n" +
  "// Source: src/tokens/components/*.css. Run `pnpm check:mcp-token-sync`.\n\n" +
  "export interface ComponentToken {\n  name: string;\n  value: string;\n  description: string;\n}\n\n" +
  "export const COMPONENT_TOKENS: ComponentToken[] = " +
  JSON.stringify(tokens, null, 2) +
  ";\n";

if (process.argv.includes("--check")) {
  let current = "";
  try {
    current = readFileSync(OUT, "utf8");
  } catch {
    /* missing → stale */
  }
  if (current !== body) {
    console.error(
      `✗ check:mcp-token-sync — ${OUT} is stale. Run \`node scripts/gen-component-tokens.mjs\`.`,
    );
    process.exit(1);
  }
  console.log(`✓ check:mcp-token-sync — ${tokens.length} component tokens documented in the MCP catalog.`);
} else {
  writeFileSync(OUT, body);
  console.log(`wrote ${OUT} (${tokens.length} tokens)`);
}
